import CustomGameCard from '../components/CustomGameCard';
import Button from '../components/base/CustomButton';

  function Game(){
    
    return <div className='game'>
    <CustomGameCard
      gameTitle={"Sediento"}
      gameEmbed={"../games/Sediento/game.html"}
      buttonText={"Clicka!"}
      maxWidth={600}
    />
     <Button
          buttonLabel="home"
          onClickNavigate="/"
        />
    </div>
  }

  export default Game;
